class RampLengthBuildingHeight:

    def __init__(self, BuildingNameDict, FloorDict, RampDict, SectionDict, FloorInSectionDict):

        self.BuildingNameDict = BuildingNameDict
        self.FloorDict = FloorDict
        self.RampDict = RampDict
        self.SectionDict = SectionDict
        self.FloorInSectionDict = FloorInSectionDict

    def split(self, start, end, seg):  # this function used for Spliting the lines
        x_delta = (end[0] - start[0]) / float(seg)
        y_delta = (end[1] - start[1]) / float(seg)
        points = []
        for i in range(1, seg):
            pts = [start[0] + i * x_delta, start[1] + i * y_delta]
            points.append(pts)
        return [start] + points + [end]

    def check_ramp_width(self, ramp_cline, ramp_lwpolygon):
        ramp_lst_data = []

        for ramp_cline1 in ramp_cline.virtual_entities():

            if ramp_cline1.dxftype() == 'LINE':

                start_ramp_cline1_pts = [ramp_cline1.dxf.start[0], ramp_cline1.dxf.start[1]]

                end_ramp_cline1_pts = [ramp_cline1.dxf.end[0], ramp_cline1.dxf.end[1]]

                cline1_pts = [start_ramp_cline1_pts, end_ramp_cline1_pts]

                np_ramp_cline1_points = np.array(cline1_pts).round(2)

                ramp_center_line1 = LineString(np_ramp_cline1_points)

                split_center_line1 = self.split(np_ramp_cline1_points[0], np_ramp_cline1_points[1], 5)

                np_center_line1_pts = np.array(split_center_line1[2]).round(2)

                np_center_line1_point = Point(np_center_line1_pts)

                # ramp polygon converting into lines

                for ramp_lwpolygon_line in ramp_lwpolygon.virtual_entities():

                    if ramp_lwpolygon_line.dxftype()=="LINE":

                        ramp_start_pts = [ramp_lwpolygon_line.dxf.start[0], ramp_lwpolygon_line.dxf.start[1]]

                        ramp_end_pts = [ramp_lwpolygon_line.dxf.end[0], ramp_lwpolygon_line.dxf.end[1]]

                        ramp_line = LineString([ramp_start_pts, ramp_end_pts])

                        if round(ramp_center_line1.distance(ramp_line)) != 0:
                            ramp_lst_data.append(round(np_center_line1_point.distance(ramp_line), 2))

        if ramp_lst_data != []:

            return min(ramp_lst_data) * 2

    def arc_angle_span_deg(self, start: float, end: float) -> float:
        """ Returns the counter clockwise angle from `start` to `end` in degrees.
        """
        # start == end is 0 by definition:
        if math.isclose(start, end):
            return 0.0

        # Special treatment for end angle == 180 deg:
        if not math.isclose(end, 360.0):
            end %= 360.0

        start %= 360.0

        if end < start:
            end += 360.0
        return end - start

    def getRampLENGTHandBuildingHeight(self):

        rampRefList = []
        try:
            for building_id, buildingNamePoly in self.BuildingNameDict.items():

                floor_dict = dict()

                for floor_id, floorNamePoly in self.FloorDict.items():

                    if buildingNamePoly[1].contains(floorNamePoly[1]) == True or round(
                            buildingNamePoly[1].distance(floorNamePoly[1]), 1) == 0.0:

                        ramp_dict = dict()

                        for ramp_id, ramp_namePoly in self.RampDict.items():

                            if floorNamePoly[1].contains(ramp_namePoly[1]) == True or round(
                                    floorNamePoly[1].distance(ramp_namePoly[1]), 1) == 0.0:

                                total_arc_length = []

                                for center_line_entity in ramp_namePoly[2].virtual_entities():

                                    if center_line_entity.dxftype() == 'LINE':

                                        line_length = LineString(
                                            [[center_line_entity.dxf.start[0], center_line_entity.dxf.start[1]],
                                             [center_line_entity.dxf.end[0], center_line_entity.dxf.end[1]]]).length

                                        total_arc_length.append(line_length)

                                    elif (center_line_entity.dxftype() == 'ARC'):

                                        start_angle = center_line_entity.dxf.start_angle

                                        end_angle = center_line_entity.dxf.end_angle

                                        arc_angle = self.arc_angle_span_deg(start_angle, end_angle)

                                        diameter = center_line_entity.dxf.radius

                                        new_arc_length = (math.pi * diameter) * (arc_angle / 180)

                                        total_arc_length.append(new_arc_length)

                                ramp_length = round(sum(map(float, total_arc_length)), 2)

                                ramp_width = self.check_ramp_width(ramp_namePoly[2], ramp_namePoly[3])

                                ramp_dict[ramp_id] = [ramp_namePoly[0], ramp_length, ramp_width]
                                rampDict = dict()
                                rampDict["RAMP_REF_ID"] = str(ramp_id)
                                rampDict["RAMP_NAME_TEXT"] = str(ramp_namePoly[0])
                                rampDict["BLDG_NAME"] = str(buildingNamePoly[0])
                                rampDict["BLDG_REF_ID"] = str(building_id)
                                rampDict["BLDG_FLOOR_KEY"] = str(
                                    buildingNamePoly[0].strip() + "-" + floorNamePoly[0].strip())
                                rampDict["FLOOR_NAME"] = str(floorNamePoly[0])
                                rampDict["FLOOR_REF_ID"] = str(ramp_id)
                                rampDict["RAMP_LENGTH"] = str(ramp_length)
                                rampDict["RAMP_WIDTH"] = str(ramp_width)

                                rampRefList.append(rampDict)

                        if len(ramp_dict) > 0:
                            floor_dict[str(floor_id)] = [str(floorNamePoly[0]), ramp_dict]
                            # print('Floor Dict ', floor_dict)

                floor_inSectionDict = dict()

                for sectionnamepoly in self.SectionDict.values():

                    if buildingNamePoly[1].contains(sectionnamepoly[1]) == True:

                        for floor_in_sect_id, floor_in_section_namepoly in self.FloorInSectionDict.items():

                            if floor_in_section_namepoly[0] != 'TDR Floor':

                                # check floor in section polygon contains section polygon

                                if sectionnamepoly[1].contains(floor_in_section_namepoly[1]) == True:
                                    floor_inSectionDict[floor_in_sect_id] = [floor_in_section_namepoly[0],
                                                                             floor_in_section_namepoly[1]]

                if (floor_dict is not None and floor_inSectionDict is not None) or (
                        floor_dict != {} and floor_inSectionDict != {}):

                    for floor_ID, floorNameRampLength in floor_dict.items():

                        for floorSECID, FloorNAMEPOLY in floor_inSectionDict.items():

                            if (str(floorNameRampLength[0]).lower() in str(FloorNAMEPOLY[0]).lower()) or (
                                    str(FloorNAMEPOLY[0]).lower() in str(floorNameRampLength[0]).lower()):
                                bounding_box = FloorNAMEPOLY[1].minimum_rotated_rectangle

                                x, y = bounding_box.exterior.coords.xy

                                edge_length = (Point(x[0], y[0]).distance(Point(x[1], y[1])),
                                               Point(x[1], y[1]).distance(Point(x[2], y[2])))

                                floor_height = f'Floor Height:{round(min(edge_length), 2)}'
                                # print('Floor Height ', floor_height)

                                floorNameRampLength.append(floor_height)
        except Exception as e:
            print(e)
            print(traceback.format_exc())
            pass
        return rampRefList

class Plot_Width_Depth:
    """
    Finding: Plot Width,Depth And Area
    """

    def __init__(self, margin_data, PlotDict, MainRoadDict):
        self.Margin_data = margin_data
        self.Plot_Data_Dict = PlotDict
        self.MainRoad_Data_Dict = MainRoadDict

    def calculate_width(self, line_blue, line_green):
        """ 1.We are checking distance Between side1 and side2
        2. returning Minimum Distance Between Side1 and side2
        3. We are getting Width of the plot from This
         """
        sub_dist = set()

        for blue in line_blue:

            for green in line_green:
                sub_dist.add(round(blue.distance(green), 1))

        return min(sub_dist)

    def find_layer_distance(self, line_pink, line_blue, line_green):
        """
        1 . Here We are checking Rear Line With Side1 and Side2
        That witch Line is touching to rear line
        2.getting All Rear line if side1 and Side2 is touching
        """
        total_lines = []

        for pink in line_pink:

            for blue in line_blue:

                if round(pink.distance(blue), 1) == 0.0:
                    total_lines.append(pink)

            for green in line_green:

                if round(pink.distance(green), 1) == 0.0:
                    total_lines.append(pink)

        return total_lines

    def mainroad_touches_with_fnt_line(self, mainroad_poly, line_red):
        '''
        1. Here We are checking MainRoad Polygon with (MarginLine) Front Line
        that Front_line points touching To MainRoad Polygon if Touches we are Returning
        True otherwise False.
        '''

        lines_points = [round(mainroad_poly.distance(lines), 1) == 0.0 for lines in line_red]

        if len(lines_points) > 0:

            return True

        else:

            return False

    def mainroad_rear_lines_point(self, mainroad_poly, line_pink):
        """
        finding mainroad polygon touch with Front Margin line or Not

        :param mainroad_poly:
        :param line_pink:
        :return:
        """
        rear_list = []

        for lines in line_pink:
            rear_list.append(round(mainroad_poly.distance(lines), 1))

        return max(rear_list)

    def MainRoadLayerData(self, _MainRoad_Entities):
        '''
        1.Checking MainRoad data and returning MainRoad ID ,MainRoad Text
        and MainRoad Polygon in The Form Of Dict
        '''
        mainroad_dict = {}

        for mainroad_lw_entity in _MainRoad_Entities:

            if (mainroad_lw_entity.dxftype() == "LWPOLYLINE" and mainroad_lw_entity.closed):

                mainroad_entity_point = [pp[0:2] for pp in mainroad_lw_entity.get_points()]
                if len(mainroad_entity_point)<3:
                    continue
                mainroad_id = mainroad_lw_entity.dxf.handle

                mainroad_lw_points = Polygon(mainroad_entity_point)

                mainroad_data_content = []

                for mainroad_text_entity in _MainRoad_Entities:

                    if mainroad_text_entity.dxftype() in ["MTEXT", "TEXT"]:

                        mainroad_text = mainroad_text_entity.dxf.text if mainroad_text_entity.dxftype() == "TEXT" else mainroad_text_entity.plain_text()

                        mainroad_text_id = mainroad_text_entity.dxf.handle

                        mainroad_text_po = (mainroad_text_entity.dxf.insert.x, mainroad_text_entity.dxf.insert.y)

                        mainroad_text_point = Point(mainroad_text_po)

                        if (mainroad_lw_points.contains(mainroad_text_point) or

                                mainroad_lw_points.touches(mainroad_text_point) or

                                round(mainroad_lw_points.distance(mainroad_text_point)) == 0):
                            mainroad_data_content.append([mainroad_id, mainroad_text, mainroad_lw_points])

                if mainroad_data_content:

                    for mainroad_data in mainroad_data_content:
                        mainroad_dict[mainroad_data[0]] = mainroad_data[1:]
                else:

                    print(f"Missing {mainroad_id} Level Of polygon")

        return mainroad_dict

    def PlotLayerData(self, _Plot_entities):
        '''
        1.Checking Plot data and returning Plot ID ,Plot Text
        and Plot Polygon in The Form Of Dict
        '''
        plot_dict = dict()

        for plot_poly in _Plot_entities:

            if plot_poly.dxftype() == "LWPOLYLINE" and plot_poly.closed:

                plot_id = plot_poly.dxf.handle
                polygon_pts = [pp[0:2] for pp in plot_poly.get_points()]
                if len(polygon_pts)<3:
                    continue
                plot_poly_pts = Polygon(polygon_pts)



                plot_list = []

                for plot_text in _Plot_entities:

                    if plot_text.dxftype() == "MTEXT" or plot_text.dxftype() == "TEXT":

                        plot_name = plot_text.dxf.text if plot_text.dxftype() == "TEXT" else plot_text.plain_text()

                        plot_text_id = plot_text.dxf.handle

                        plot_text_pts = Point([plot_text.dxf.insert[0], plot_text.dxf.insert[1]])

                        if plot_poly_pts.contains(plot_text_pts) == True or plot_poly_pts.touches(
                                plot_text_pts) == True or round(plot_poly_pts.distance(plot_text_pts), 1) == 0.0:
                            plot_list.append([plot_text_id, plot_name, plot_poly_pts])

                if plot_list != [] or plot_list is not None:

                    for plot_data in plot_list:
                        plot_dict[plot_data[0]] = plot_data[1:]

                else:

                    print(f"plot({plot_id}) doesn't found Any Text")

        return plot_dict

    def plot_check_margin_line(self, plot_polygon, line_pts):
        '''1.Checking Margin Line Points Width Plot Polygon That Plot Polygon
        Touching Margin Line Points or Not
        2. If Touching Return True otherwise False
         '''

        plot_check_margin_line = []

        for line_points in line_pts:

            if round(plot_polygon.distance(line_points), 1) == 0.0:
                plot_check_margin_line.append(True)

        if all(plot_check_margin_line) == True:

            return True

        else:

            return False

    def Check_plot_area(self, plot_level_poly):
        """Finding Plot Area"""
        plot_area = round(plot_level_poly.area, 2)

        return plot_area

    def get_plotwidthdepth(self):
        '''1. Providing FolderName And FileName
        2 Calling And Executing  All Function
        3. We are returning a Dict..
        4.in this Dict returning Plot ID , Plot Name
         , Plot Dept and Plot Width'''
        xall_data_list = []
        try:

            all_data_list = []
            for side_name, side_lines in self.Margin_data.items():
                all_data_list.extend(side_lines)

            for plot_id, plot_level_poly in self.Plot_Data_Dict.items():

                plot_area = self.Check_plot_area(plot_level_poly[1])

                # 1 sending two Argument After That making this function condition

                if (self.plot_check_margin_line(plot_level_poly[1], all_data_list)) == True:

                    for mairaod_id, mainroad_poly in self.MainRoad_Data_Dict.items():

                        # 1 sending two Argument After That making this function condition

                        if self.mainroad_touches_with_fnt_line(mainroad_poly[1], self.Margin_data.get('FRONT')) == True:

                            depth = self.mainroad_rear_lines_point(mainroad_poly[1], self.Margin_data.get('REAR'))

                            width = self.calculate_width(self.Margin_data.get('SIDE1'), self.Margin_data.get('SIDE2'))

                            dist_dict = dict()

                            dist_dict["PLOT_ID"] = plot_id

                            dist_dict["PLOT_NAME"] = plot_level_poly[0]

                            dist_dict["PLOT_DEPTH"] = depth

                            dist_dict["PLOT_WIDTH"] = width

                            dist_dict["PLOT_AREA"] = plot_area

                            xall_data_list.append(dist_dict)

                        else:

                            print(f"MainRoad ({mairaod_id})Does Not Touches to Front Line")

                else:

                    print(f"Margin_line does Not Touch to plot line")
        except Exception as e:
            print(e)
            print(traceback.format_exc())
            pass
        return xall_data_list

class SegmentwisePlotLength_AND_EntGateWidth:
    """
    Finding Segmentwise Plot Length and Entry Gate Width
    -----------------------------------------------------
    """

    def __init__(self, AccessoryUseData, PlotDict, margin_data, MainRoadDict):

        self.AccessoryUseData = AccessoryUseData
        self.PlotDict = PlotDict
        self.Margin_data = margin_data
        self.MainRoad_Data_Dict = MainRoadDict

    def EntGateWidth(self, entgatepolygon):

        """Finding Width Of Entry Gate"""

        bbox = entgatepolygon.minimum_rotated_rectangle

        x, y = bbox.boundary.coords.xy

        length_width = [Point([x[0], y[0]]).distance(Point([x[1], y[1]])),
                        Point([x[1], y[1]]).distance(Point([x[2], y[2]])),
                        Point([x[2], y[2]]).distance(Point([x[3], y[3]])),
                        Point([x[3], y[3]]).distance(Point([x[4], y[4]]))]

        return round(min(length_width), 2)

    def PlotSegmentLength(self, PlotPolygon):
        """Finding Length Of Plot Segments.
            ex:[p1-p2:10.20,p2-p3:40.10]
        """
        b = PlotPolygon.exterior.coords

        listlineString = [(f'p{lin + 1}-p{lin + 2}', b[lin:lin + 2]) for lin in range(len(b) - 2)] + [
            (f'p{len(b) - 1}-p{1}', [b[-2], b[-1]])]

        listlineString = [[ls[0], round(LineString(ls[1]).length, 2)] for ls in listlineString]

        return listlineString

    def AccessoryUse_layer(self, AccessoryUseData):

        """
        Finding Entry Gate Label and Polygon

        :param AccessoryUseData  of entities:
        :return dict of entry gate id,entry gate label and entry gate polygon:
        """

        AccessoryUseDict = dict()
        AccessoryUseContainLabels = []

        for AccessoryUse_id, AccessoryUse_entity in AccessoryUseData.items():

            if 'gate' in AccessoryUse_entity[0].lower():
                AccessoryUseContainLabels.append([AccessoryUse_id, AccessoryUse_entity[0], AccessoryUse_entity[1]])

        if AccessoryUseContainLabels != [] and len(AccessoryUseContainLabels) > 0:
            for acessoryUse in AccessoryUseContainLabels:
                AccessoryUseDict[acessoryUse[0]] = [acessoryUse[1], acessoryUse[2]]

        return AccessoryUseDict

    def getPlotLength_And_EntGateWidth(self):
        """
        :param msp:
         getting Modelspace information
        :return final list of plot segment length and entry gate width:
        ex:[{'PLOT_REF':st3,'PLOT_NAME':plot,p1-p2:30.34,p2-p3:40.34,'PLOT_WIDTH':10.24,'PLOT_DEPTH':12.34,'PLOT_AREA':34.56},
        {'ENTGATE_REF':34dt,'ENTGATE_NAME':'ent.gate','ENTGATE_WIDTH':0.2}]
        """

        returnValueList = []

        try:

            AccessoryUseDict = self.AccessoryUse_layer(self.AccessoryUseData)

            tmpPlotdict = dict()

            for handle_id, LabelPoly in self.PlotDict.items():

                tmpPlotdict["PLOT_REF"] = handle_id
                tmpPlotdict["PLOT_NAME"] = LabelPoly[0]

                plot_lengthsegment = self.PlotSegmentLength(LabelPoly[1])

                for segment_labelLength in plot_lengthsegment:
                    tmpPlotdict[segment_labelLength[0]] = segment_labelLength[1]

            plot_area_width_depth = Plot_Width_Depth(self.Margin_data, self.PlotDict, self.MainRoad_Data_Dict)

            return_plot_area_width_depth = plot_area_width_depth.get_plotwidthdepth()
            # print(return_plot_area_width_depth)
            for data in return_plot_area_width_depth:

                tmpPlotdict["PLOT_WIDTH"] = str(data.get("PLOT_WIDTH"))
                tmpPlotdict["PLOT_DEPTH"] = str(data.get("PLOT_DEPTH"))
                tmpPlotdict["PLOT_AREA"] = str(data.get("PLOT_AREA"))

            if tmpPlotdict != {} and len(tmpPlotdict) > 0:
                returnValueList.append(tmpPlotdict)

            tmpentgatedict = dict()

            for handle_id, LabelPoly in AccessoryUseDict.items():
                gate_width = self.EntGateWidth(LabelPoly[1])
                tmpentgatedict["ENTGATE_REF"] = str(handle_id)
                tmpentgatedict["ENTGATE_NAME"] = str(LabelPoly[0])
                tmpentgatedict["ENTGATE_WIDTH"] = str(gate_width)

            if tmpentgatedict != {} and len(tmpentgatedict) > 0:
                returnValueList.append(tmpentgatedict)
        except Exception as e:
            print(e)
            print(traceback.format_exc())
            pass
        return returnValueList

